You can use this cloud function to manage books. Here is the example code for testing the invocation of this cloud function in the mini-program:

```js
// Create a book
wx.cloud
  .callFunction({
    name: 'book-management',
    data: {
      action: 'createBook',
      data: {
        title: 'The Three-Body Problem',
        author: 'Liu Cixin',
        price: 39.9,
        isbn: '9787536692930',
      },
    },
  })
  .then((res) => {
    console.log('Creation successful:', res);
  });

// Update a book
wx.cloud
  .callFunction({
    name: 'book-management',
    data: {
      action: 'updateBook',
      data: {
        id: 'xxx', // Book ID
        book: {
          price: 45.0,
        },
      },
    },
  })
  .then((res) => {
    console.log('Update successful:', res);
  });

// Delete a book
wx.cloud
  .callFunction({
    name: 'book-management',
    data: {
      action: 'deleteBook',
      data: {
        id: 'xxx', // Book ID
      },
    },
  })
  .then((res) => {
    console.log('Deletion successful:', res);
  });

// Get a single book
wx.cloud
  .callFunction({
    name: 'book-management',
    data: {
      action: 'getBook',
      data: {
        id: 'xxx', // Book ID
      },
    },
  })
  .then((res) => {
    console.log('Book information:', res);
  });

// Get book list
wx.cloud
  .callFunction({
    name: 'book-management',
    data: {
      action: 'listBooks',
      data: {},
    },
  })
  .then((res) => {
    console.log('Book list:', res);
  });

// Search books
wx.cloud
  .callFunction({
    name: 'book-management',
    data: {
      action: 'searchBooks',
      data: {
        keyword: 'The Three-Body Problem',
      },
    },
  })
  .then((res) => {
    console.log('Search results:', res);
  });

```

